package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Proxy;
import java.lang.reflect.InvocationHandler;
import java.lang.reflect.Method;

class ReflectionAccessFilterHelperTest {

  @Test
  void testIsAnyPlatformType_androidType() {
    // Android type class name that triggers isAndroidType
    Class<?> androidClass = AndroidTypeMock.class;
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(androidClass));
  }

  @Test
  void testIsAnyPlatformType_kotlinPackage() {
    Class<?> kotlinClass = KotlinTypeMock.class;
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(kotlinClass));
  }

  @Test
  void testIsAnyPlatformType_kotlinxPackage() {
    Class<?> kotlinxClass = KotlinxTypeMock.class;
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(kotlinxClass));
  }

  @Test
  void testIsAnyPlatformType_scalaPackage() {
    Class<?> scalaClass = ScalaTypeMock.class;
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(scalaClass));
  }

  @Test
  void testIsAnyPlatformType_otherPackage() {
    Class<?> otherClass = OtherTypeMock.class;
    assertFalse(ReflectionAccessFilterHelper.isAnyPlatformType(otherClass));
  }

  // Mock classes with specific package names for testing
  static class AndroidTypeMock {
    @Override
    public String toString() {
      return "android.mock.Class";
    }
  }

  static class KotlinTypeMock {}

  static class KotlinxTypeMock {}

  static class ScalaTypeMock {}

  static class OtherTypeMock {}

  // Use a dynamic proxy to simulate Class<?> with custom getName()
  private static Class<?> createClassWithName(String name) {
    return (Class<?>) Proxy.newProxyInstance(
      ReflectionAccessFilterHelper.class.getClassLoader(),
      new Class<?>[] { Class.class },
      new InvocationHandler() {
        @Override
        public Object invoke(Object proxy, Method method, Object[] args) throws Throwable {
          if ("getName".equals(method.getName()) && (args == null || args.length == 0)) {
            return name;
          }
          // For other methods, throw UnsupportedOperationException
          throw new UnsupportedOperationException("Method " + method.getName() + " is not supported by proxy");
        }
      });
  }

  @Test
  void testIsAnyPlatformType_variousNames() throws Exception {
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(createClassWithName("android.mock.Class")));
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(createClassWithName("kotlin.SomeClass")));
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(createClassWithName("kotlinx.SomeClass")));
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(createClassWithName("scala.SomeClass")));
    assertFalse(ReflectionAccessFilterHelper.isAnyPlatformType(createClassWithName("com.example.SomeClass")));
  }
}
